export type ParsedSettleEscrowInstruction<
  TProgram extends string = typeof ARCADIUM_ESCROW_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    client: TAccountMetas[0];
    config: TAccountMetas[1];
    escrowVaultState: TAccountMetas[2];
    escrowVault: TAccountMetas[3];
    recipientTokenAccount: TAccountMetas[4];
    treasuryTokenAccount: TAccountMetas[5];
    tokenMint: TAccountMetas[6];
    tokenProgram: TAccountMetas[7];
  };
  data: SettleEscrowInstructionData;
};

export function parseSettleEscrowInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedSettleEscrowInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 8) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 8,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      client: getNextAccount(),
      config: getNextAccount(),
      escrowVaultState: getNextAccount(),
      escrowVault: getNextAccount(),
      recipientTokenAccount: getNextAccount(),
      treasuryTokenAccount: getNextAccount(),
      tokenMint: getNextAccount(),
      tokenProgram: getNextAccount(),
    },
    data: getSettleEscrowInstructionDataDecoder().decode(instruction.data),
  };
}
